console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');
console.log(`Items reГ§us: ${items.length}`);

const notifications = {};

items.forEach(item => {
  const data = item.json;

  let destinatairePrincipal;
  let codeDestinataire;
  let typeDestinataire;

  if (data.niveau_escalade === 'PDG') {
    destinatairePrincipal = {
      code: data.code_pdg,
      nom: data.nom_pdg,
      prenom: data.prenom_pdg,
      email: data.email_pdg,
      telephone: data.telephone_pdg,
      chat_id: data.chat_id_pdg,
      langue: data.langue_pdg,
      bot: data.bot_pdg
    };
    codeDestinataire = data.code_pdg;
    typeDestinataire = 'PDG';

  } else if (data.niveau_escalade === 'DGA') {
    destinatairePrincipal = {
      code: data.code_dga,
      nom: data.nom_dga,
      prenom: data.prenom_dga,
      email: data.email_dga || null,
      telephone: data.telephone_dga || null,
      chat_id: null,
      langue: data.langue_dga || 'FRA',
      bot: null
    };
    codeDestinataire = data.code_dga;
    typeDestinataire = 'DGA';

  } else if (data.niveau_escalade === 'SUPERIEUR') {
    destinatairePrincipal = {
      code: data.code_sup_createur,
      nom: data.nom_sup_createur,
      prenom: data.prenom_sup_createur,
      email: data.email_sup_createur,
      telephone: data.tel_sup_createur,
      chat_id: data.chat_id_superieur,
      langue: data.langue_superieur,
      bot: data.bot_superieur
    };
    codeDestinataire = data.code_sup_createur;
    typeDestinataire = 'SUPERIEUR';

  // APRГ€S
  } else if (data.niveau_escalade === 'SALARIE') {
      destinatairePrincipal = {
        code: data.code_createur,
        nom: data.nom_createur,
        prenom: data.prenom_createur,
        email: data.email_createur,
        telephone: data.tel_createur,
        chat_id: data.chat_id_createur,
        langue:  data.langue_createur || 'FRA',
        bot:     data.bot_createur
      };
      codeDestinataire = data.code_createur;
      typeDestinataire = 'SALARIE';

  } else if (data.niveau_escalade === 'FARHAT') {
    destinatairePrincipal = {
      code: data.code_farhat,
      nom: data.nom_farhat,
      prenom: data.prenom_farhat,
      email: data.email_farhat || null,
      telephone: data.telephone_farhat || null,
      chat_id: data.chat_id_farhat || null,
      langue: data.langue_farhat || 'FRA',
      bot: data.bot_farhat || null
    };
    codeDestinataire = data.code_farhat;
    typeDestinataire = 'FARHAT';

  } else if (data.niveau_escalade === 'BAALLAH') {
    destinatairePrincipal = {
      code: data.code_baallah,
      nom: data.nom_baallah,
      prenom: data.prenom_baallah,
      email: data.email_baallah || null,
      telephone: data.telephone_baallah || null,
      chat_id: data.chat_id_baallah || null,
      langue: data.langue_baallah || 'FRA',
      bot: data.bot_baallah || null
    };
    codeDestinataire = data.code_baallah;
    typeDestinataire = 'BAALLAH';

  } else {
    console.log(`вЏ­пёЏ  SalariГ© ${data.code_salarie} ignorГ© (niveau: ${data.niveau_escalade})`);
    return;
  }

  const cleDestinataire = `${typeDestinataire}_${codeDestinataire}`;

  if (!notifications[cleDestinataire]) {
    notifications[cleDestinataire] = {
      destinataire_principal: destinatairePrincipal,
      type_destinataire: typeDestinataire,
      niveau_escalade: data.niveau_escalade,

