const resultats = Object.values(notifications).map(notif => {
  const totalSalaries = notif.salaries.length;
  const joursMin = Math.min(...notif.salaries.map(s => s.jours_restants));
  const joursMax = Math.max(...notif.salaries.map(s => s.jours_restants));
  const delaiTotal = parseInt(notif.salaries[0]?.delai_int) || 10;
  const seuilDga = notif.salaries[0]?.seuil_dga || Math.floor(delaiTotal / 2);

  let emailCC   = [];
  let chatIDsCC = [];

  if (notif.type_destinataire === 'PDG') {
    if (notif.superieur.email)   emailCC.push(notif.superieur.email);
    if (notif.salarie.email)     emailCC.push(notif.salarie.email);
    if (notif.superieur.chat_id) chatIDsCC.push({
      chat_id: notif.superieur.chat_id, bot: notif.superieur.bot,
      langue: notif.superieur.langue,
      nom: `${notif.superieur.prenom} ${notif.superieur.nom}`
    });
    if (notif.salarie.chat_id) chatIDsCC.push({
      chat_id: notif.salarie.chat_id, bot: notif.salarie.bot,
      langue: notif.salarie.langue,
      nom: `${notif.salarie.prenom} ${notif.salarie.nom}`
    });

  } else if (notif.type_destinataire === 'SUPERIEUR') {
    if (notif.salarie.email)   emailCC.push(notif.salarie.email);
    if (notif.salarie.chat_id) chatIDsCC.push({
      chat_id: notif.salarie.chat_id, bot: notif.salarie.bot,
      langue: notif.salarie.langue,
      nom: `${notif.salarie.prenom} ${notif.salarie.nom}`
    });

  } else if (notif.type_destinataire === 'BAALLAH') {
    // BAALLAH в†’ pas de CC
  } else if (notif.type_destinataire === 'FARHAT') {
    // FARHAT в†’ pas de CC
  } else if (notif.type_destinataire === 'DGA') {
    // DGA в†’ email uniquement, pas de CC
  }

  return {
    destinataire_principal: notif.destinataire_principal,
    type_destinataire:      notif.type_destinataire,
    niveau_escalade:        notif.niveau_escalade,
    email_cc:    emailCC.length   > 0 ? emailCC.join(',') : null,
    telegram_cc: chatIDsCC.length > 0 ? chatIDsCC         : null,
    salarie:   notif.salarie,
    superieur: notif.superieur,
    createur:  notif.createur,
    pdg:       notif.pdg,
    dga:       notif.dga,
    farhat:    notif.farhat,
    baallah:   notif.baallah,
    salaries:  notif.salaries,
    statistiques: {
      total_salaries: totalSalaries,
      jours_min:      joursMin,
      jours_max:      joursMax,
      priorite:       notif.niveau_escalade,
      delai_total:    delaiTotal,
      seuil_dga:      seuilDga
    },
    meta: {
      date_traitement:       new Date().toISOString(),
      langue_message:        notif.destinataire_principal.langue || 'FRA',
      peut_envoyer_email:    !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!notif.destinataire_principal.chat_id
    }
  };
});

console.log(`\nвњ… Notifications structurГ©es: ${resultats.length}`);
