  telegramMessage += `в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\n`;
  telegramMessage += `рџ‘¤ *${destinataire.prenom} ${destinataire.nom}*\n\n`;
  telegramMessage += `рџ“Љ *${T.section_stats}*\n`;
  telegramMessage += `${T.total} : *${stats.total_salaries}*\n`;
  telegramMessage += `${T.delai_min} : *${stats.jours_min} ${T.jours}*\n\n`;
  telegramMessage += `рџ‘Ґ *${T.section_salaries}*\n\n`;

  // APRГ€S
  salaries.slice(0, 5).forEach((sal, index) => {
      telegramMessage += `${index + 1}. ${getEmoji(sal.jours_restants)} *${sal.prenom} ${sal.nom}*\n`;
      telegramMessage += `   рџ“Ѓ NВ° Dossier : \`${sal.code_salarie}\`\n`;
      if (sal.poste)   telegramMessage += `   рџ’ј ${sal.poste}\n`;
      if (sal.service) telegramMessage += `   рџЏў ${sal.service}\n`;
      telegramMessage += `   вЏ° ${sal.jours_restants} ${T.jours} ${T.jours_restants}\n`;
      // вњ… NOUVEAU : CrГ©ateur
      if (sal.user_createur) {
        telegramMessage += `   рџ‘¤ CrГ©ateur : ${sal.nom_createur || sal.user_createur}\n`;
      }
      telegramMessage += `\n`;
  });
  if (salaries.length > 5) telegramMessage += `... et ${salaries.length - 5} autre(s) salariГ©(s)\n\n`;
  if (stats.jours_min <= 2) telegramMessage += `рџљЁ *${T.urgent}*\n\n`;

  return {
    email:    { subject: emailSubject, body: emailBody },
    telegram: { text: telegramMessage, parse_mode: 'Markdown' }
  };
}

function genererMessageCC(data, destinataireCC, typeDestinatairePrincipal) {
  const langue = destinataireCC.langue || data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const stats = data.statistiques;
  const salaries = data.salaries;
  const destinatairePrincipal = data.destinataire_principal;

  const labels = {
    SUPERIEUR: T.cc_message.votre_superieur,
    PDG:       T.cc_message.le_pdg,
    DGA:       T.cc_message.le_dga,
    FARHAT:    T.cc_message.le_farhat,
    BAALLAH:   T.cc_message.le_baallah
  };
  const label = labels[typeDestinatairePrincipal] || typeDestinatairePrincipal;
  const msg_envoye_a       = `${label} *${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}*`;
  const msg_envoye_a_email = `${label} ${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}`;

  let emailSubject = `${T.copie_info} вЂ” ${T.sujet_email[typeDestinatairePrincipal]} вЂ” ${stats.total_salaries} salariГ©(s)`;

  let emailBody = `${T.salutation} ${destinataireCC.prenom} ${destinataireCC.nom},\n\n`;
  emailBody += `${T.cc_message.base} ${msg_envoye_a_email}.\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau : ${data.niveau_escalade} | ${T.total} : ${stats.total_salaries} | ${T.delai_min} : ${stats.jours_min} ${T.jours}\n\n`;
  emailBody += `в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n`;
  emailBody += `рџ‘Ґ ${T.section_salaries}\n`;
  emailBody += `в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n\n`;

  salaries.forEach((sal, index) => {
    emailBody += `${index + 1}. ${getEmoji(sal.jours_restants)} ${sal.prenom} ${sal.nom} (${sal.code_salarie})\n`;
    emailBody += `   вЏ° ${sal.jours_restants} ${T.jours} ${T.jours_restants} (${T.date_limite} : ${formaterDate(sal.date_limite, langue)})\n`;
    if (sal.jours_restants <= 2) emailBody += `   рџљЁ ${T.urgent}\n`;
    emailBody += `\n`;
  });

  emailBody += `${T.cc_message.action}\n\n`;
  emailBody += `${T.cordialement},\n\n${T.signature}\n`;
  emailBody += `в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n`;
  emailBody += `рџ¤– ${T.message_auto} | ${T.copie_info} | ${T.ne_pas_repondre}\n`;

  let telegramMessage = `${T.copie_info}\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\n`;
  telegramMessage += `${T.salutation} *${destinataireCC.prenom} ${destinataireCC.nom}*,\n\n`;
  telegramMessage += `${T.cc_message.base} ${msg_envoye_a}.\n\n`;
  telegramMessage += `рџ“Љ ${T.total} : *${stats.total_salaries}* | ${T.delai_min} : *${stats.jours_min} ${T.jours}*\n\n`;
  telegramMessage += `рџ‘Ґ *${T.section_salaries}*\n\n`;

  salaries.slice(0, 3).forEach((sal, index) => {
    telegramMessage += `${index + 1}. ${getEmoji(sal.jours_restants)} *${sal.prenom} ${sal.nom}*\n`;
    telegramMessage += `   вЏ° ${sal.jours_restants} ${T.jours} ${T.jours_restants}\n\n`;
  });
  if (salaries.length > 3) telegramMessage += `... et ${salaries.length - 3} autre(s) salariГ©(s)\n\n`;
  telegramMessage += `${T.cc_message.action}\n`;

  return {
    email:    { subject: emailSubject, body: emailBody },
    telegram: { text: telegramMessage, parse_mode: 'Markdown' }
  };
}

const results = [];

inputData.forEach(item => {
  const data = item.json;
  const messagesPrincipal = genererMessagePrincipal(data);

  results.push({
    json: {
      ...data,
      messages:           messagesPrincipal,
      type_envoi:         'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      meta: { ...data.meta, langue_utilisee: data.meta.langue_message || 'FRA', date_generation: new Date().toISOString() }
    }
  });

  // CC : SUPERIEUR в†’ copie au salariГ©
  if (data.type_destinataire === 'SUPERIEUR' && data.salarie?.chat_id) {
    const messagesCC = genererMessageCC(data, data.salarie, 'SUPERIEUR');
    results.push({ json: {
      ...data, messages: messagesCC, type_envoi: 'CC',
      destinataire_final: data.salarie, cc_pour_profil: 'SALARIE',
      meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() }
    }});
  }

  // CC : PDG в†’ copie au supГ©rieur + copie au salariГ©
  if (data.type_destinataire === 'PDG') {
    if (data.superieur?.chat_id) {
      const msgCCSup = genererMessageCC(data, data.superieur, 'PDG');
      results.push({ json: {
        ...data, messages: msgCCSup, type_envoi: 'CC',
        destinataire_final: data.superieur, cc_pour_profil: 'SUPERIEUR',
        meta: { ...data.meta, langue_utilisee: data.superieur.langue || 'FRA', date_generation: new Date().toISOString() }
      }});
    }
    if (data.salarie?.chat_id) {
      const msgCCSal = genererMessageCC(data, data.salarie, 'PDG');
      results.push({ json: {
        ...data, messages: msgCCSal, type_envoi: 'CC',
        destinataire_final: data.salarie, cc_pour_profil: 'SALARIE',
        meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() }
      }});
    }
  }

  // CC : BAALLAH в†’ copie au salariГ©
  if (data.type_destinataire === 'BAALLAH' && data.salarie?.chat_id) {
    const messagesCC = genererMessageCC(data, data.salarie, 'BAALLAH');
    results.push({ json: {
      ...data, messages: messagesCC, type_envoi: 'CC',
      destinataire_final: data.salarie, cc_pour_profil: 'SALARIE',
      meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() }
    }});
  }

  // CC : FARHAT в†’ copie au salariГ©
  if (data.type_destinataire === 'FARHAT' && data.salarie?.chat_id) {
    const messagesCC = genererMessageCC(data, data.salarie, 'FARHAT');
    results.push({ json: {
      ...data, messages: messagesCC, type_envoi: 'CC',
      destinataire_final: data.salarie, cc_pour_profil: 'SALARIE',
      meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() }
    }});
  }
  // DGA в†’ email uniquement, pas de CC, pas de Telegram
});

